THE RISK:
{
 "id": "frankfurt-grid-queue-de-slip",
 "title": "A single metro's 24–36-month grid queue gates ~37% of the CE TAM's Year-1 flow",
 "narrative": "Germany is 0.50 of the base and Frankfurt hosts ~75% of German IT capacity — so roughly 37% of the venture's TAM routes through one metro's grid interconnection queue, where waits now run 24–36 months and vacancy is 2.2%. The model treats DE as a diversified half of the market; in the first-12-months window it is really a bet that Frankfurt's 542 MW under construction energizes on schedule. If 2026 energizations slip right — grid queue, plus EnEfG efficiency/heat-reuse compliance adding commissioning friction — the fit-outs that would generate the venture's largest tranche of Year-1 PDU purchase orders move to 2027–28 while the 9% trend stays intact on paper.",
 "category": "exogenous",
 "targetNodes": [
  "geo.DE",
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Frankfurt grid connections face 24–36-month waits while 542 MW sits under construction and 383 MW in planning — energization slots, not demand, set commissioning dates",
   "refs": [
    "digest:geo-DE#c15",
    "digest:geo-DE#c8",
    "digest:geo-DE#c14"
   ]
  },
  {
   "step": "propagation",
   "text": "Frankfurt is ~75% of German capacity and DE is 0.50 of the CE base, so a queue slip in one metro defers the largest single block of near-term fit-out demand; PDU POs land at fit-out, so deferred energization means deferred orders regardless of the 2030 CAGR",
   "refs": [
    "digest:geo-DE#c1",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "model-impact",
   "text": "DE's effective share of the in-window demand flow falls toward the installed-load low bound (0.42) and the Year-1 obtainable pace drops with it — the funnel's biggest geography becomes 2028 revenue",
   "refs": [
    "ledger:geo.DE",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "The ledger carries country-level shares that look diversified across seven markets; there is no metro dimension, so the fact that half the funnel physically routes through one substation queue is structurally invisible. The DE band (0.42–0.53) reads as scope uncertainty, not as a timing gate.",
 "expectedObviousness": "medium",
 "falsifier": "TenneT/regional grid operator commitments (or JLL Frankfurt prints) showing Frankfurt live IT load stepping up by >100 MW within the venture's Year-1, i.e. the 542 MW under construction energizing on schedule.",
 "likelihood": {
  "value": 0.45,
  "rationale": "Queue lengths and near-zero vacancy are documented; offsetting, projects already under construction typically hold secured grid allocations, so slippage hits the planning cohort harder than the UC cohort. [evidence revision: The grid-queue premise, near-zero vacancy, and EnEfG commissioning friction are all strongly corroborated, and grid remediation (TenneT/Amprion substations) is confirmed to be mid-2030s planning-stage with no near-term >100 MW live-load step-up — meaning the falsifier remains unmet. This nudges likelihood up modestly. However, the concurrent finding that new capacity is migrating to Rhine-Main/tier-two sites outside the single Frankfurt queue (NTT FRA6, JLL 'New Geography' report) weakens the '37% funnels through one metro's queue' framing, capping the upward revision.]",
  "basis": "evidence",
  "revisedFrom": 0.4
 },
 "perturbation": [
  {
   "nodeId": "geo.DE",
   "op": "set",
   "value": 0.42,
   "note": "DE share of contestable in-window demand falls to the installed-load low bound as Frankfurt additions slip"
  },
  {
   "nodeId": "obtainableFactor",
   "op": "scale",
   "value": 0.6,
   "note": "Year-1 pace compressed as the largest geography's fit-outs defer"
  }
 ],
 "indicators": [
  {
   "signal": "Frankfurt live IT-load and under-construction prints",
   "where": "JLL German data center market updates and Mordor Frankfurt series",
   "threshold": "<+50 MW live-load growth across two consecutive half-year prints",
   "updates": "increases"
  },
  {
   "signal": "Grid-connection queue length and energization commitments for Rhein-Main data-center applicants",
   "where": "TenneT/Amprion connection disclosures and Hesse permitting dockets; operator capex-call commentary on Frankfurt energization dates",
   "threshold": "Stated waits lengthening beyond 36 months or named projects re-guiding commissioning by ≥2 quarters",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission an energization-date audit of the Frankfurt 542 MW under-construction pipeline (which projects hold firm grid allocations for 2026)",
   "type": "information",
   "voiNodeId": "geo.DE",
   "note": "Separates timing risk from level risk in the DE share"
  },
  {
   "action": "Rebalance the Year-1 territory plan toward Berlin (219 MW in planning) and Poland/CEE, where additions are less grid-queue-bound",
   "type": "strategic",
   "voiNodeId": null,
   "note": null
  },
  {
   "action": "Launch a retrofit/replacement SKU program for operating Frankfurt halls whose demand does not depend on new grid connections",
   "type": "operational",
   "voiNodeId": null,
   "note": null
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Germany's Data Center Strategy vs. AI Energy Demand",
   "sourceType": "industry-report",
   "publisher": "innobu",
   "date": "2026-04-01",
   "excerpt": "In Frankfurt, 126 data centers account for up to 40 percent of city-wide power consumption, and new grid connections are unavailable until the mid-2030s. The Energy Efficiency Act requires operators to source 100 percent renewable electricity by January 2027, reuse at least 10 percent of waste heat from July 2026, and maintain a maximum PUE of 1.2 for new facilities.",
   "url": "https://www.innobu.com/en/articles/data-center-strategy-ai-energy-demand.html",
   "attached": true
  },
  {
   "title": "Frankfurt's Data Center Market Has Hit a Physical Wall",
   "sourceType": "industry-report",
   "publisher": "KiTalent",
   "date": "2026-03-01",
   "excerpt": "Available utility capacity for new large-scale developments within Frankfurt city limits is effectively zero. High-voltage grid connections now carry wait times of 24 to 36 months. The Energy Efficiency Act mandates PUE of 1.2 or better from 2026 onward.",
   "url": "https://kitalent.com/articles/frankfurt-data-center-talent-crisis",
   "attached": true
  },
  {
   "title": "TenneT, Uniper Partner for Power Station for Frankfurt Region",
   "sourceType": "industry-report",
   "publisher": "Rigzone",
   "date": "2026-01-25",
   "excerpt": "Uniper and TenneT agreed to develop a new central network node in Grosskrotzenburg to serve data center-driven growth in power demand in the greater Frankfurt area, targeting to start operation earlier than planned.",
   "url": "https://www.rigzone.com/news/tennet_uniper_partner_for_power_station_for_frankfurt_region-25-jan-2026-182841-article/",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://kitalent.com/articles/frankfurt-data-center-talent-crisis",
   "stance": "supports",
   "quote": "Available utility capacity for new large-scale developments within Frankfurt city limits is effectively zero. High-voltage grid connections now carry wait times of 24 to 36 months. The Energy Efficiency Act mandates PUE of 1.2 or better from 2026 onward."
  },
  {
   "url": "https://www.innobu.com/en/articles/data-center-strategy-ai-energy-demand.html",
   "stance": "supports",
   "quote": "In Frankfurt, 126 data centers account for up to 40 percent of city-wide power consumption, and new grid connections are unavailable until the mid-2030s."
  },
  {
   "url": "https://neospaces.de/en/insights/frankfurt-data-center-fra1-power-2026-q2",
   "stance": "supports",
   "quote": "But 2026 is the year the historically dominant growth story inside the city itself runs into a hard physical wall: power capacity."
  },
  {
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "stance": "supports",
   "quote": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced."
  },
  {
   "url": "https://www.rigzone.com/news/tennet_uniper_partner_for_power_station_for_frankfurt_region-25-jan-2026-182841-article/",
   "stance": "contradicts",
   "quote": "The core of the project is the construction of a new 380-kilovolt switchyard, which will create extensive additional capacity for urgently needed customer connections in the Rhine-Main area"
  },
  {
   "url": "https://www.heise.de/en/news/482-Megawatts-Gigantic-Data-Center-in-Reinhessen-11118489.html",
   "stance": "contradicts",
   "quote": "The Japanese company NTT Data plans to build one of the largest data centers in Germany and Europe starting in 2027. \"NTT Frankfurt 6\" will be built on the 75-hectare site of a former US barracks in Rheinhessen, about 40 kilometers from Frankfurt's city center."
  }
 ]
}

